#include <vector>
#include <unordered_map>
#include <algorithm>

using namespace std;

long long solve(vector<long long> nums, long long k) {
    long long prefix_sum = 0;
    unordered_map<long long, long long> mod_map;
    mod_map[0] = -1;
    vector<pair<long long, long long>> segments;
    long long n = nums.size();

    for (long long i = 0; i < n; ++i) {
        prefix_sum += nums[i];
        long long mod = prefix_sum % k;
        if (mod < 0) mod += k; // Ensure mod is non-negative
        if (mod_map.find(mod) != mod_map.end()) {
            long long start = mod_map[mod] + 1;
            segments.emplace_back(start, i);
            mod_map.clear();
            mod_map[0] = i;
            prefix_sum = 0;
        } else {
            mod_map[mod] = i;
        }
    }

    sort(segments.begin(), segments.end());
    vector<long long> res;
    long long last_end = -1;

    for (auto &seg : segments) {
        long long start = seg.first;
        long long end = seg.second;
        if (start > last_end) {
            for (long long i = last_end + 1; i < start; ++i) {
                res.push_back(nums[i]);
            }
            last_end = end;
        } else {
            if (end > last_end) {
                for (long long i = last_end + 1; i <= end; ++i) {
                    res.push_back(nums[i]);
                }
                last_end = end;
            }
        }
    }

    if (segments.empty()) {
        res = nums;
    } else {
        for (long long i = last_end + 1; i < n; ++i) {
            res.push_back(nums[i]);
        }
    }

    long long sum = 0;
    for (long long num : res) {
        sum += num;
    }
    return sum;
}
